import secrets
import base64
from cryptography.fernet import Fernet
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
import os

# Generate a secure key from configuration
def generate_encryption_key(password: str, salt: bytes = None) -> bytes:
    if salt is None:
        salt = secrets.token_bytes(16)
    
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=salt,
        iterations=100000,
    )
    key = base64.urlsafe_b64encode(kdf.derive(password.encode()))
    return key, salt

# Encrypt credit card number
def encrypt_credit_card(card_number: str, encryption_key: bytes) -> str:
    f = Fernet(encryption_key)
    encrypted_card = f.encrypt(card_number.encode())
    return base64.urlsafe_b64encode(encrypted_card).decode()

# Decrypt credit card number
def decrypt_credit_card(encrypted_card: str, encryption_key: bytes) -> str:
    f = Fernet(encryption_key)
    encrypted_data = base64.urlsafe_b64decode(encrypted_card.encode())
    decrypted_card = f.decrypt(encrypted_data)
    return decrypted_card.decode()

# Example usage
if __name__ == "__main__":
    # In production, load from secure config
    config_password = os.environ.get('ENCRYPTION_PASSWORD', 'default_secure_password')
    key, salt = generate_encryption_key(config_password)
    
    # Example card
    card_number = "4532015112830366"
    
    # Encrypt
    encrypted = encrypt_credit_card(card_number, key)
    print(f"Encrypted: {encrypted}")
    
    # Decrypt
    decrypted = decrypt_credit_card(encrypted, key)
    print(f"Decrypted: {decrypted}")